function startWizard(){
  wizStep=0;
  wizData=freshWizData();
  document.getElementById('loginScreen').style.display='none';
  document.getElementById('wizard').classList.add('active');
  renderWizard();
}
function exitWizard(){
  document.getElementById('wizard').classList.remove('active');
  document.getElementById('loginScreen').style.display='grid';
}
function wizNext(){ if(wizStep<WIZ_TOTAL-1){wizStep++;renderWizard();window.scrollTo(0,0);} }
function wizBack(){ if(wizStep>0){wizStep--;renderWizard();window.scrollTo(0,0);} }

function renderWizard(){
  document.getElementById('wizBar').style.width=((wizStep+1)/WIZ_TOTAL*100)+'%';
  const w=document.getElementById('wizWrap');
  const steps=[wizAbout,wizTasks,wizRequirements,wizDataForm,wizQuestionnaire,wizContracts,wizDeclaration,wizIdSelfie,wizAgb,wizDone];
  w.innerHTML='<div class="wiz-step active">'+steps[wizStep]()+'</div>';
  if(wizStep===5) setTimeout(initSignPads,30);
}
