function petPick(el){
  if(el.textContent==='Keine Haustiere'){ document.querySelectorAll('#wz_pets .check').forEach(x=>{if(x!==el)x.classList.remove('on');}); el.classList.toggle('on'); }
  else { const none=[...document.querySelectorAll('#wz_pets .check')].find(x=>x.textContent==='Keine Haustiere'); if(none)none.classList.remove('on'); el.classList.toggle('on'); }
}
function saveWizData(){
  wizData.first=val('wz_first');wizData.last=val('wz_last');wizData.email=val('wz_email');
  wizData.phone=val('wz_phone');wizData.area=val('wz_area');
  const g=document.querySelector('#wz_gender button.on');wizData.gender=g?g.dataset.v:'';
  wizData.citizenship=document.getElementById('wz_citizen').value;
  wizData.skills=[...document.querySelectorAll('#wz_skills .check.on')].map(e=>e.textContent);
  wizData.pets=[...document.querySelectorAll('#wz_pets .check.on')].map(e=>e.textContent);
  wizData.motivation=val('wz_motiv');
  if(!wizData.first||!wizData.last){toast('Bitte Vor- und Nachnamen ausfüllen',true);return;}
  if(!wizData.email||wizData.email.indexOf('@')<1){toast('Bitte gültige E-Mail eingeben',true);return;}
  if(!wizData.phone){toast('Bitte Telefonnummer eingeben',true);return;}
  if(!wizData.area){toast('Bitte Wohnort eingeben',true);return;}
  if(!wizData.gender){toast('Bitte Geschlecht wählen',true);return;}
  if(!wizData.citizenship){toast('Bitte Staatsbürgerschaft/Arbeitserlaubnis wählen',true);return;}
  if(!wizData.skills.length){toast('Bitte mindestens eine Leistung wählen',true);return;}
  if(!wizData.pets.length){toast('Bitte Angabe zu Haustieren machen',true);return;}
  wizNext();
}

