// --- Validierungs-Helfer ---
function validTaxId(v){ return /^\d{11}$/.test((v||'').replace(/\s/g,'')); }
function validKvNr(v){ return /^[A-Za-z]\d{9}$/.test((v||'').replace(/\s/g,'')); }
function validIban(v){
  v=(v||'').replace(/\s/g,'').toUpperCase();
  if(!/^DE\d{20}$/.test(v)) return false;
  const re=v.slice(4)+v.slice(0,4);
  const num=re.replace(/[A-Z]/g,c=>c.charCodeAt(0)-55);
  let rem=0; for(let i=0;i<num.length;i++){ rem=(rem*10+parseInt(num[i],10))%97; }
  return rem===1;
}
