function pfbOtherJobChange(){
  const v=document.getElementById('pf_otherjob').value;
  document.getElementById('pf_studentbox').style.display=(v==='Ja, Student')?'block':'none';
}
function handleEnrollFile(input){
  const file=input.files&&input.files[0]; if(!file)return;
  if(file.size>6*1024*1024){ toast('Datei zu groß (max. 6 MB)',true); input.value=''; return; }
  const reader=new FileReader();
  reader.onload=function(e){
    wizData.enrollmentFile=true;
    wizData.enrollmentImg=e.target.result;
    renderWizard();
    toast('Immatrikulationsbescheinigung hochgeladen');
  };
  reader.readAsDataURL(file);
}
function savePfb(){
  const q=wizData.questionnaire||{};
  q.street=val('pf_street');q.houseNo=val('pf_houseno');q.plz=val('pf_plz');q.city=val('pf_city');
  q.address=(q.street+' '+q.houseNo+', '+q.plz+' '+q.city).trim();
  q.birth=val('pf_birth');q.taxId=val('pf_taxid');q.kvNr=val('pf_kvnr');q.kasse=val('pf_kasse');q.iban=val('pf_iban');
  q.employment=document.getElementById('pf_employment').value;
  q.otherJob=document.getElementById('pf_otherjob').value;
  wizData.questionnaire=q;
  wizData.first=val('pf_first');wizData.last=val('pf_last');
  // Pflichtprüfung
  if(!q.street||!q.houseNo||!q.plz||!q.city){toast('Bitte die komplette Anschrift ausfüllen',true);return;}
  if(!q.birth){toast('Bitte Geburtsdatum angeben',true);return;}
  if(!validTaxId(q.taxId)){toast('Steuer-ID muss aus genau 11 Ziffern bestehen',true);return;}
  if(!validKvNr(q.kvNr)){toast('KV-Nummer: 1 Buchstabe gefolgt von 9 Ziffern',true);return;}
  if(!q.kasse){toast('Bitte Krankenkasse angeben',true);return;}
  if(!validIban(q.iban)){toast('Bitte eine gültige deutsche IBAN eingeben',true);return;}
  if(!q.employment){toast('Bitte Beschäftigungsart wählen',true);return;}
  if(!q.otherJob){toast('Bitte Angabe zu weiterer Beschäftigung machen',true);return;}
  if(q.otherJob==='Nein'){toast('Eine Bewerbung ist nur mit Studenten- oder Hauptbeschäftigungsstatus möglich.',true);return;}
  wizData.isStudent=(q.otherJob==='Ja, Student');
  if(wizData.isStudent){
    toast('Hinweis: Im Schritt „Ausweis & Selfie" benötigen wir noch deine Immatrikulationsbescheinigung.');
  }
  wizNext();
}
function fillContract(text){
  const name=((wizData.first||'')+' '+(wizData.last||'')).trim();
  const q=wizData.questionnaire||{};
  const nameMitAnschrift = name + (q.address?(', '+q.address):'');
  const taetigkeit=(wizData.skills&&wizData.skills.length)?wizData.skills.join(' / '):'Alltagshilfe';
  let t=text;
  // Platzhalter in allen Vertragsarten füllen
  t=t.split('[Name und Anschrift Arbeitnehmer]').join(nameMitAnschrift);
  t=t.split('[Mitarbeiter / Auftragnehmer]').join(nameMitAnschrift);
  t=t.split('[Mitarbeiter/Auftragnehmer]').join(nameMitAnschrift);
  t=t.split('[Mitarbeiter]').join(name);
  t=t.split('[Tätigkeitsbezeichnung]').join(taetigkeit);
  // Beschäftigungsdaten, falls vorhanden
  if(q.address){ t=t.split('[Anschrift]').join(q.address); }
  return t;
}
function wizContracts(){
  const docs=Object.keys(wizData.docs);
  return wizNumLabel(6)+
  '<div class="wiz-card"><h2>Verträge lesen & unterschreiben</h2>'+
  '<p class="lead">Deine Angaben wurden bereits in den Arbeitsvertrag übernommen. Bitte öffne jedes Dokument, lies es und unterschreibe (wie auf dem Personalausweis).</p>'+
  docs.map((d,i)=>'<div class="doc-item"><div class="doc-head" onclick="toggleDoc('+i+')"><div class="dt">📄 '+d+'</div><div class="doc-state" id="docstate-'+i+'">'+(wizData.docs[d]?'<span style="color:var(--good)">✓ signiert</span>':'öffnen')+'</div></div>'+
    '<div class="doc-body" id="docbody-'+i+'"><div class="doc-text">'+fillContract(DOC_TEXTS[d])+'</div>'+
    '<label style="font-size:12px;font-weight:600;color:var(--muted)">Deine Unterschrift:</label>'+
    '<div class="sign-pad" id="signpad-'+i+'" data-doc="'+d+'" data-idx="'+i+'"><canvas></canvas><div class="sign-hint" id="signhint-'+i+'">Hier unterschreiben</div></div>'+
    '<div class="sign-actions"><button class="btn-ghost btn-sm" onclick="clearSign('+i+')">Löschen</button><button class="btn-primary btn-sm" style="width:auto" onclick="confirmSign('+i+',\''+d+'\')">Unterschrift bestätigen</button></div>'+
    '</div></div>').join('')+
  '<div class="wiz-nav"><button class="btn-ghost" onclick="wizBack()">← Zurück</button><button class="btn-primary" onclick="checkContracts()">Weiter →</button></div></div>';
}
