/* ---- Unterschrift-Canvas ---- */
function initSignPads(){
  document.querySelectorAll('.sign-pad').forEach(pad=>{
    const canvas=pad.querySelector('canvas');
    if(canvas.dataset.init)return;
    // Canvas-interne Auflösung exakt an die angezeigte Canvas-Größe koppeln
    const rect=canvas.getBoundingClientRect();
    if(rect.width===0||rect.height===0)return; // noch nicht sichtbar – später erneut
    canvas.dataset.init='1';
    const idx=pad.dataset.idx;
    canvas.width=rect.width;canvas.height=rect.height;
    const ctx=canvas.getContext('2d');
    ctx.strokeStyle='#0a444a';ctx.lineWidth=2.4;ctx.lineCap='round';ctx.lineJoin='round';
    let drawing=false,last=null;
    const pos=(e)=>{
      const r=canvas.getBoundingClientRect();
      const t=e.touches&&e.touches[0]?e.touches[0]:e;
      // Skalierung berücksichtigen, falls CSS-Größe ≠ interne Größe
      const sx=canvas.width/r.width, sy=canvas.height/r.height;
      return {x:(t.clientX-r.left)*sx, y:(t.clientY-r.top)*sy};
    };
    const start=(e)=>{drawing=true;last=pos(e);const h=document.getElementById('signhint-'+idx);if(h)h.style.display='none';e.preventDefault();};
    const move=(e)=>{if(!drawing)return;const p=pos(e);ctx.beginPath();ctx.moveTo(last.x,last.y);ctx.lineTo(p.x,p.y);ctx.stroke();last=p;canvas.dataset.drawn='1';e.preventDefault();};
    const end=()=>{drawing=false;last=null;};
    canvas.addEventListener('mousedown',start);
    canvas.addEventListener('mousemove',move);
    window.addEventListener('mouseup',end);
    canvas.addEventListener('touchstart',start,{passive:false});
    canvas.addEventListener('touchmove',move,{passive:false});
    canvas.addEventListener('touchend',end);
  });
}
function clearSign(i){
  const pad=(i==='gen')?document.getElementById('genSignPad'):document.getElementById('signpad-'+i);
  if(!pad)return;
  const canvas=pad.querySelector('canvas');
  const ctx=canvas.getContext('2d');ctx.clearRect(0,0,canvas.width,canvas.height);
  canvas.dataset.drawn='';const h=document.getElementById('signhint-'+i);if(h)h.style.display='grid';
}
function confirmSign(i,doc){
  const pad=document.getElementById('signpad-'+i);const canvas=pad.querySelector('canvas');
  if(!canvas.dataset.drawn){toast('Bitte zuerst unterschreiben',true);return;}
  wizData.docs[doc]=true;
  // Unterschriftsbild als Daten-URL sichern (für Speicherung beim Mitarbeiter)
  wizData.signatures=wizData.signatures||{};
  try{ wizData.signatures[doc]=canvas.toDataURL('image/png'); }catch(e){}
  document.getElementById('docstate-'+i).innerHTML='<span style="color:var(--good)">✓ signiert</span>';
  document.getElementById('docbody-'+i).classList.remove('open');
  toast(doc+' signiert');
}
