function viewLegal(which){
  const t=which==='agb'
    ? 'ALLGEMEINE GESCHÄFTSBEDINGUNGEN (DailyDo)\n\n§1 Geltungsbereich\nDiese AGB gelten für die Vermittlung von Alltagshilfe-Dienstleistungen über die Plattform DailyDo.\n\n§2 Leistungen\nDailyDo vermittelt Helfer:innen an hilfesuchende Personen für Haushalt, Einkäufe, Begleitdienste und weitere Alltagsleistungen.\n\n§3 Pflichten der Mitarbeiter\nMitarbeiter verpflichten sich zu zuverlässiger, sorgfältiger Leistungserbringung und zur Einhaltung der vereinbarten Termine.\n\n§4 Vergütung\nDie Abrechnung erfolgt auf Basis der erfassten und vom Kunden bestätigten Stunden.\n\n§5 Haftung\nEs gelten die gesetzlichen Haftungsregelungen.\n\n(Demo-Text – die endgültigen AGB werden vor dem Echtbetrieb juristisch erstellt.)'
    : 'DATENSCHUTZERKLÄRUNG (DailyDo)\n\n1. Verantwortlicher\nDailyDo, Alltagshilfe Hannover.\n\n2. Verarbeitete Daten\nWir verarbeiten die im Bewerbungs- und Einsatzprozess angegebenen personenbezogenen Daten (Name, Kontaktdaten, Ausweisdaten, Steuer- und Sozialversicherungsdaten) ausschließlich zum Zweck der Beschäftigung und Einsatzvermittlung.\n\n3. Rechtsgrundlage\nArt. 6 Abs. 1 DSGVO sowie § 26 BDSG (Beschäftigtendatenschutz).\n\n4. Speicherung\nDie Daten werden auf Servern in der EU (Frankfurt) gespeichert und nur so lange aufbewahrt, wie es gesetzlich erforderlich ist.\n\n5. Deine Rechte\nDu hast das Recht auf Auskunft, Berichtigung, Löschung und Widerspruch.\n\n(Demo-Text – die endgültige Datenschutzerklärung wird vor dem Echtbetrieb juristisch erstellt.)';
  document.getElementById('modalTitle').textContent=which==='agb'?'AGB':'Datenschutzerklärung';
  document.getElementById('modalBody').innerHTML='<div class="doc-text" style="max-height:60vh;white-space:pre-wrap">'+t+'</div>';
  document.getElementById('modalFoot').innerHTML='<button class="btn-ghost" onclick="closeModal()">Schließen</button>';
  openModal();
}
